#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        static int freq[100005];
        memset(freq,0,(N+2)*sizeof(int));
        int maxf=0, x;
        for(int i=0;i<N;i++){
            scanf("%d",&x);
            ++freq[x];
            if(freq[x]>maxf) maxf=freq[x];
        }
        printf("%d\n", N-maxf);
    }
    return 0;
}

