import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        freq = {}
        maxf = 0
        for _ in range(N):
            x = int(next(it))
            cnt = freq.get(x,0)+1
            freq[x] = cnt
            if cnt > maxf:
                maxf = cnt
        out.append(str(N - maxf))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

